// Find messages due for send: scheduled_at <= now, message_type='step2', no twilio_sid yet
const now = new Date().toISOString();

const res = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages?message_type=eq.step2&twilio_sid=is.null&scheduled_at=lte.${encodeURIComponent(now)}&select=id,conversation_id,body,conversations(lead_phone,opted_out,status,client_id,clients(respondfall_number,system_active))`,
  {
    headers: {
      apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
      Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
    },
  }
);
const messages = await res.json();

const eligible = messages.filter(m => {
  const conv = m.conversations;
  if (!conv) return false;
  if (conv.opted_out) return false;
  if (!conv.clients?.system_active) return false;
  return true;
});

// For each, check no inbound reply exists after the scheduled message
const toSend = [];
for (const msg of eligible) {
  const replyRes = await fetch(
    `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages?conversation_id=eq.${msg.conversation_id}&direction=eq.inbound&select=id`,
    {
      headers: {
        apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
        Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
      },
    }
  );
  const replies = await replyRes.json();
  if (replies.length === 0) toSend.push(msg);
}

return toSend.map(m => ({ json: m }));
